 60→    editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: asm.id });
 61→  };
 62→
 63→  const handleSelectAssembly = (assemblyId) => {
 64→    editorDispatch({
 65→      type: 'SET_ACTIVE_ASSEMBLY',
 66→      assemblyId: activeAssemblyId === assemblyId ? null : assemblyId,
 67→    });
 68→  };
 69→
 70→  const handleDeleteAssembly = (e, assemblyId) => {
 71→    e.stopPropagation();
 72→    dispatch({ type: 'ASSEMBLY_DELETE', assemblyId });
 73→    if (activeAssemblyId === assemblyId) {
 74→      editorDispatch({ type: 'SET_ACTIVE_ASSEMBLY', assemblyId: null });
 75→    }
