  1→import { detectRoomFaces } from '@/geometry/roomDetection';
  2→import { distanceToSegment } from '@/geometry/line';
  3→import { add, distance, midpoint, normalize, perpendicular, scale, subtract } from '@/geometry/point';
  4→import { pointInPolygon } from '@/geometry/polygon';
  5→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
  6→import { formatMeasurement } from './format';
  7→import { ANNOTATION_SEMANTIC_ROLES, ANNOTATION_TRUST_LEVELS, createMeasurementMetadata } from './policy';
  8→
  9→const EPSILON = 1e-6;
 10→const WALL_DIMENSION_GAP = 300;
 11→const ROOM_DIMENSION_INSET = 180;
 12→const OVERALL_CHAIN_GAP = 500;
 13→const OVERALL_TOTAL_GAP = 900;
 14→const ARROW_SIZE = 80;
 15→const VALUE_MERGE_TOLERANCE = 1;
 16→const MIN_DIMENSION_LENGTH = 100;
 17→
 18→function normalizeTextAngle(angleDeg) {
 19→  return angleDeg > 90 || angleDeg < -90 ? angleDeg + 180 : angleDeg;
 20→}
 21→
 22→function createArrowHead(tip, direction, size = ARROW_SIZE) {
 23→  const dir = normalize(direction);
 24→  const normal = perpendicular(dir);
 25→  const back = scale(dir, -size);
 26→  const side = scale(normal, size * 0.45);
 27→  return {
 28→    tip,
 29→    left: add(add(tip, back), side),
 30→    right: add(add(tip, back), scale(side, -1)),
 31→  };
 32→}
 33→
 34→function buildAlignedFigure(startPoint, endPoint, offset) {
 35→  const direction = normalize(subtract(endPoint, startPoint));
 36→  if (Math.abs(direction.x) < EPSILON && Math.abs(direction.y) < EPSILON) return null;
 37→
 38→  const normal = perpendicular(direction);
 39→  const offsetVector = scale(normal, offset);
 40→  const lineStart = add(startPoint, offsetVector);
 41→  const lineEnd = add(endPoint, offsetVector);
 42→  const angle = normalizeTextAngle(Math.atan2(direction.y, direction.x) * (180 / Math.PI));
 43→
 44→  return {
 45→    lineStart,
 46→    lineEnd,
 47→    extensionLines: [
 48→      { start: startPoint, end: lineStart },
 49→      { start: endPoint, end: lineEnd },
 50→    ],
 51→    textPosition: midpoint(lineStart, lineEnd),
 52→    textAngle: angle,
 53→    measurement: distance(startPoint, endPoint),
 54→    direction,
 55→  };
 56→}
 57→
 58→function buildHorizontalFigure(startPoint, endPoint, offset) {
 59→  const left = startPoint.x <= endPoint.x ? startPoint : endPoint;
 60→  const right = left === startPoint ? endPoint : startPoint;
 61→  const y = (startPoint.y + endPoint.y) / 2 + offset;
 62→  const lineStart = { x: left.x, y };
 63→  const lineEnd = { x: right.x, y };
 64→
 65→  return {
 66→    lineStart,
 67→    lineEnd,
 68→    extensionLines: [
 69→      { start: left, end: lineStart },
 70→      { start: right, end: lineEnd },
 71→    ],
 72→    textPosition: midpoint(lineStart, lineEnd),
 73→    textAngle: 0,
 74→    measurement: Math.abs(endPoint.x - startPoint.x),
 75→    direction: { x: 1, y: 0 },
 76→  };
 77→}
 78→
 79→function buildVerticalFigure(startPoint, endPoint, offset) {
 80→  const top = startPoint.y <= endPoint.y ? startPoint : endPoint;
 81→  const bottom = top === startPoint ? endPoint : startPoint;
 82→  const x = (startPoint.x + endPoint.x) / 2 + offset;
 83→  const lineStart = { x, y: top.y };
 84→  const lineEnd = { x, y: bottom.y };
 85→
 86→  return {
 87→    lineStart,
 88→    lineEnd,
 89→    extensionLines: [
 90→      { start: top, end: lineStart },
 91→      { start: bottom, end: lineEnd },
 92→    ],
 93→    textPosition: midpoint(lineStart, lineEnd),
 94→    textAngle: 90,
 95→    measurement: Math.abs(endPoint.y - startPoint.y),
 96→    direction: { x: 0, y: 1 },
 97→  };
 98→}
 99→
100→export function createDimensionFigure({
101→  id,
102→  startPoint,
103→  endPoint,
104→  mode = 'aligned',
105→  offset = 0,
106→  label,
107→  source = 'manual',
108→  sourceType = null,
109→  sourceId = null,
110→}) {
111→  let core = null;
112→
113→  if (mode === 'horizontal') core = buildHorizontalFigure(startPoint, endPoint, offset);
114→  else if (mode === 'vertical') core = buildVerticalFigure(startPoint, endPoint, offset);
115→  else core = buildAlignedFigure(startPoint, endPoint, offset);
116→
117→  if (!core || core.measurement < MIN_DIMENSION_LENGTH) return null;
118→
119→  const lineDirection = normalize(subtract(core.lineEnd, core.lineStart));
120→  const startArrow = createArrowHead(core.lineStart, lineDirection);
121→  const endArrow = createArrowHead(core.lineEnd, scale(lineDirection, -1));
122→  const measurementMeta = createMeasurementMetadata(core.measurement);
123→
124→  return {
125→    id,
126→    type: 'dimension',
127→    trustLevel: ANNOTATION_TRUST_LEVELS.AUTHORITATIVE,
128→    semanticRole: ANNOTATION_SEMANTIC_ROLES.MEASUREMENT,
129→    source,
130→    sourceType,
131→    sourceId,
132→    mode,
133→    measurement: core.measurement,
134→    measurementMeta,
135→    label: label || measurementMeta.displayValue,
136→    lineStart: core.lineStart,
137→    lineEnd: core.lineEnd,
138→    extensionLines: core.extensionLines,
139→    arrowheads: [startArrow, endArrow],
140→    text: {
141→      position: core.textPosition,
142→      angle: core.textAngle,
143→      value: label || measurementMeta.displayValue,
144→    },
145→    segments: [
146→      { start: core.lineStart, end: core.lineEnd },
147→      ...core.extensionLines,
148→      { start: startArrow.tip, end: startArrow.left },
149→      { start: startArrow.tip, end: startArrow.right },
150→      { start: endArrow.tip, end: endArrow.left },
151→      { start: endArrow.tip, end: endArrow.right },
152→    ],
153→  };
154→}
155→
156→function isInsideAnyFace(point, faces) {
157→  return faces.some((face) => pointInPolygon(point, face.points));
158→}
159→
160→function pickWallDimensionFigure(renderWall, faces, wallId) {
161→  const offset = renderWall.thickness / 2 + WALL_DIMENSION_GAP;
162→  const negative = createDimensionFigure({
163→    id: `wall-dim-${wallId}-neg`,
164→    startPoint: renderWall.start,
165→    endPoint: renderWall.end,
166→    mode: 'aligned',
167→    offset: -offset,
168→    source: 'derived',
169→    sourceType: 'wall',
170→    sourceId: wallId,
171→  });
172→  if (!negative) return null;
173→  if (!faces.length) return negative;
174→
175→  const positive = createDimensionFigure({
176→    id: `wall-dim-${wallId}-pos`,
177→    startPoint: renderWall.start,
178→    endPoint: renderWall.end,
179→    mode: 'aligned',
180→    offset,
181→    source: 'derived',
182→    sourceType: 'wall',
183→    sourceId: wallId,
184→  });
185→  if (!positive) return negative;
186→
187→  const negativeInside = isInsideAnyFace(negative.text.position, faces);
188→  const positiveInside = isInsideAnyFace(positive.text.position, faces);
189→
190→  if (negativeInside && !positiveInside) return positive;
191→  if (positiveInside && !negativeInside) return negative;
192→  return negative;
193→}
194→
195→export function buildWallDimensionFigures(walls = [], columns = []) {
196→  const faces = detectRoomFaces(walls, columns || []);
197→
198→  return walls
199→    .map((wall) => {
200→      const renderWall = getWallRenderData(wall, columns || []).renderWall;
201→      return pickWallDimensionFigure(renderWall, faces, wall.id);
202→    })
203→    .filter(Boolean);
204→}
