206→export function buildRoomDimensionFigures(rooms = []) {
207→  const figures = [];
208→
209→  for (const room of rooms) {
210→    if (!room.points?.length) continue;
211→
212→    const xs = room.points.map((point) => point.x);
213→    const ys = room.points.map((point) => point.y);
214→    const minX = Math.min(...xs);
215→    const maxX = Math.max(...xs);
216→    const minY = Math.min(...ys);
217→    const maxY = Math.max(...ys);
218→
219→    const horizontal = createDimensionFigure({
220→      id: `room-dim-h-${room.id}`,
221→      startPoint: { x: minX, y: minY },
222→      endPoint: { x: maxX, y: minY },
223→      mode: 'horizontal',
224→      offset: ROOM_DIMENSION_INSET,
225→      source: 'derived',
226→      sourceType: 'room',
227→      sourceId: room.id,
228→    });
229→
230→    const vertical = createDimensionFigure({
231→      id: `room-dim-v-${room.id}`,
232→      startPoint: { x: maxX, y: minY },
233→      endPoint: { x: maxX, y: maxY },
234→      mode: 'vertical',
235→      offset: -ROOM_DIMENSION_INSET,
236→      source: 'derived',
237→      sourceType: 'room',
238→      sourceId: room.id,
239→    });
240→
241→    if (horizontal) figures.push(horizontal);
242→    if (vertical) figures.push(vertical);
243→  }
244→
245→  return figures;
246→}
247→
248→function uniqueSortedValues(values = []) {
249→  const sorted = [...values].sort((a, b) => a - b);
250→  return sorted.filter((value, index) => (
251→    index === 0 || Math.abs(value - sorted[index - 1]) > VALUE_MERGE_TOLERANCE
252→  ));
253→}
254→
255→export function buildOverallDimensionFigures(walls = [], columns = []) {
256→  const renderWalls = walls
257→    .map((wall) => getWallRenderData(wall, columns || []).renderWall)
258→    .filter(Boolean);
259→
260→  const points = renderWalls.flatMap((wall) => [wall.start, wall.end]);
261→  if (points.length < 2) return [];
262→
263→  const xs = points.map((point) => point.x);
264→  const ys = points.map((point) => point.y);
265→  const minX = Math.min(...xs);
266→  const maxX = Math.max(...xs);
267→  const minY = Math.min(...ys);
268→  const maxY = Math.max(...ys);
269→  const chainX = uniqueSortedValues(xs);
270→  const chainY = uniqueSortedValues(ys);
271→  const figures = [];
272→
273→  for (let index = 0; index < chainX.length - 1; index += 1) {
274→    const figure = createDimensionFigure({
275→      id: `overall-chain-x-${index}`,
276→      startPoint: { x: chainX[index], y: minY },
277→      endPoint: { x: chainX[index + 1], y: minY },
278→      mode: 'horizontal',
279→      offset: -OVERALL_CHAIN_GAP,
280→      source: 'derived',
281→      sourceType: 'overall-chain',
282→    });
283→    if (figure) figures.push(figure);
284→  }
285→
286→  for (let index = 0; index < chainY.length - 1; index += 1) {
287→    const figure = createDimensionFigure({
288→      id: `overall-chain-y-${index}`,
289→      startPoint: { x: minX, y: chainY[index] },
290→      endPoint: { x: minX, y: chainY[index + 1] },
291→      mode: 'vertical',
292→      offset: -OVERALL_CHAIN_GAP,
293→      source: 'derived',
294→      sourceType: 'overall-chain',
295→    });
296→    if (figure) figures.push(figure);
297→  }
298→
299→  const overallWidth = createDimensionFigure({
300→    id: 'overall-width',
301→    startPoint: { x: minX, y: minY },
302→    endPoint: { x: maxX, y: minY },
303→    mode: 'horizontal',
304→    offset: -OVERALL_TOTAL_GAP,
305→    source: 'derived',
306→    sourceType: 'overall',
307→  });
308→
309→  const overallHeight = createDimensionFigure({
310→    id: 'overall-height',
311→    startPoint: { x: minX, y: minY },
312→    endPoint: { x: minX, y: maxY },
313→    mode: 'vertical',
314→    offset: -OVERALL_TOTAL_GAP,
315→    source: 'derived',
316→    sourceType: 'overall',
317→  });
318→
319→  if (overallWidth) figures.push(overallWidth);
320→  if (overallHeight) figures.push(overallHeight);
321→
322→  return figures;
323→}
324→
325→export function buildManualDimensionFigures(annotations = []) {
326→  return annotations
327→    .filter((annotation) => annotation.type === 'dimension')
328→    .map((annotation) => createDimensionFigure({
329→      id: annotation.id,
330→      startPoint: annotation.startPoint,
331→      endPoint: annotation.endPoint,
332→      mode: annotation.mode,
333→      offset: annotation.offset,
334→      label: annotation.textOverride?.trim() || undefined,
335→      source: 'manual',
336→      sourceType: 'annotation',
337→      sourceId: annotation.id,
338→    }))
339→    .filter(Boolean);
340→}
341→
342→export function hitTestDimensionFigure(point, figure, tolerance) {
343→  return figure.segments.some((segment) => distanceToSegment(point, segment.start, segment.end) <= tolerance);
344→}
